        "plt.bar(monthly_df['YearMonth'], monthly_df['Number_of_Bookings'],\n",
        "        width=20, color='skyblue', edgecolor='darkblue', alpha=0.7)\n",
        "plt.title(' Monthly Room Bookings (Bar View)')\n",
        "plt.xlabel('Month')\n",
        "plt.ylabel('Number of Bookings')\n",
