        "# Make sure EquipmentList is string type and handle missing values\n",
        "dfbookingdataset5['EquipmentList'] = dfbookingdataset5['EquipmentList'].astype(str).str.strip()\n",
        "\n",
        "# Split by comma and explode into individual equipment items\n",
        "equipment_split = dfbookingdataset5['EquipmentList'].str.split(',', expand=False).explode()\n",
        "\n",
        "# Clean: remove extra spaces and normalize\n",
        "equipment_split = equipment_split.str.strip().str.title()  # Title case for consistency"
