        "# Count total bookings per building\n",
        "bookings_by_building = dfbookingdataset5.groupby('Building_Title').size().reset_index(name='Total_Bookings')\n",
        "\n",
        "# Merge with room summary to get booking activity\n",
        "room_summary_with_books = room_summary.merge(bookings_by_building, on='Building_Title', how='left')\n",
