        "team_booking_counts = dfbookingdataset5['Team_Title'].value_counts().sort_values(ascending=False)\n",
        "\n",
        "# Top 15 (Active) and Bottom 15 (Low Activity)\n",
        "top_15 = team_booking_counts.head(15)\n",
        "bottom_15 = team_booking_counts.tail(15)\n",
        "\n",
        "# Save the details\n",
        "top_15_df = pd.DataFrame(top_15).reset_index()\n",
        "top_15_df.columns = ['Team_Title', 'Booking_Count']\n",
        "top_15_df['Activity_Level'] = 'Top 15 (High Activity)'\n",
        "\n",
        "bottom_15_df = pd.DataFrame(bottom_15).reset_index()\n",
        "bottom_15_df.columns = ['Team_Title', 'Booking_Count']\n",
        "bottom_15_df['Activity_Level'] = 'Bottom 15 (Low Activity)'\n",
        "\n",
        "# Join the two file\n",
        "team_activity_summary = pd.concat([top_15_df, bottom_15_df], ignore_index=True)\n",
        "\n",
        "# Save to CSV\n",
        "team_activity_summary.to_csv('team_booking_activity_summary.csv', index=False)\n",
        "\n",
        "# Create subplots\n",
        "fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(14, 8))\n",
        "\n",
        "# Top 15 Teams\n",
        "ax1.bar(top_15.index, top_15.values, color='skyblue', edgecolor='black')\n",
        "ax1.set_title('Top 15 Teams (High Activity)', fontweight='bold')\n",
        "ax1.set_ylabel('Number of Bookings')\n",
        "ax1.set_xlabel('Team')\n",
        "ax1.tick_params(axis='x', rotation=60)\n",
        "\n",
        "# Bottom 15 Teams\n",
        "ax2.bar(bottom_15.index, bottom_15.values, color='lightcoral', edgecolor='black')\n",
        "ax2.set_title('Bottom 15 Teams (Low Activity)', fontweight='bold')\n",
        "ax2.set_ylabel('Number of Bookings')\n",
        "ax2.set_xlabel('Team')\n",
        "ax2.tick_params(axis='x', rotation=60)\n",
        "\n",
        "# Layout\n",
        "plt.tight_layout()\n",
        "# Save the plot\n",
        "plt.savefig('team_booking_activity_plot.png', dpi=300, bbox_inches='tight')\n",
        "plt.show()"
