        "# Get top and bottom 15 teams\n",
        "top_15_teams_list = top_15_teams['Team_Title'].tolist()\n",
        "bottom_15_teams_list = bottom_15_teams['Team_Title'].tolist()\n",
        "\n",
        "# Filter dataset\n",
        "df_top = dfbookingdataset5[dfbookingdataset5['Team_Title'].isin(top_15_teams_list)]\n",
        "df_bottom = dfbookingdataset5[dfbookingdataset5['Team_Title'].isin(bottom_15_teams_list)]\n",
        "\n",
        "# Count booking types\n",
        "top_type = df_top['BookingType_Title'].value_counts().head(15)\n",
        "bottom_type = df_bottom['BookingType_Title'].value_counts().head(15)\n",
        "\n",
        "# Convert to DataFrames for saving\n",
        "top_type_df = top_type.reset_index()\n",
        "top_type_df.columns = ['BookingType_Title', 'Top_15_Teams_Booking_Count']\n",
        "top_type_df['Rank'] = top_type_df.index + 1\n",
        "\n",
        "bottom_type_df = bottom_type.reset_index()\n",
        "bottom_type_df.columns = ['BookingType_Title', 'Bottom_15_Teams_Booking_Count']\n",
        "bottom_type_df['Rank'] = bottom_type_df.index + 1\n",
        "\n",
        "# Merge the result for comparison\n",
        "booking_type_comparison = pd.merge(\n",
        "    top_type_df[['BookingType_Title', 'Top_15_Teams_Booking_Count']],\n",
        "    bottom_type_df[['BookingType_Title', 'Bottom_15_Teams_Booking_Count']],\n",
        "    on='BookingType_Title',\n",
        "    how='outer'\n",
        ").fillna(0).astype({'Top_15_Teams_Booking_Count': 'int', 'Bottom_15_Teams_Booking_Count': 'int'})\n",
        "\n",
        "booking_type_comparison['Total'] = (\n",
        "    booking_type_comparison['Top_15_Teams_Booking_Count'] +\n",
        "    booking_type_comparison['Bottom_15_Teams_Booking_Count']\n",
        ")\n",
        "booking_type_comparison = booking_type_comparison.sort_values('Total', ascending=False)\n",
        "\n",
        "# Save all results\n",
        "top_type_df.to_csv('top_15_teams_booking_types.csv', index=False)\n",
        "bottom_type_df.to_csv('bottom_15_teams_booking_types.csv', index=False)\n",
        "booking_type_comparison.to_csv('booking_types_top_vs_bottom_teams.csv', index=False)\n",
